) : TestWatcher() {
    override fun starting(description: Description) {
        Dispatchers.setMain(dispatcher)
    }

    override fun finished(description: Description) {
        Dispatchers.resetMain()
    }
}

class ControlledSearchRepository : SearchRepository {
    private val requests = mutableMapOf<String, CompletableDeferred<List<Job>>>()

    override suspend fun search(query: String): List<Job> {
        val deferred = CompletableDeferred<List<Job>>()
        requests[query] = deferred
        return deferred.await()
    }

    fun complete(query: String, value: List<Job>) {
        requests.getValue(query).complete(value)
    }

    fun fail(query: String, error: Throwable) {
        requests.getValue(query).completeExceptionally(error)
    }
}

